use kreuzcrawl::create_engine;
use kreuzcrawl::scrape;
mod common;
mod mock_server;
#[allow(unused_imports)]
use mock_server::{MockRoute, MockServer};

/// Port 9 (discard) is deliberately chosen: SSRF policy rejects the URL
/// before any TCP connection attempt, so the test does not depend on
/// a listening server.
const LOOPBACK_URL: &str = "http://127.0.0.1:9/";

#[tokio::test]
async fn test_ssrf_loopback_denied_by_default() {
    // Default config: deny_private = true. Loopback must be rejected before connect.
    let engine = create_engine(None).expect("engine creation should succeed with default config");
    let result = scrape(&engine, LOOPBACK_URL).await;
    assert!(result.is_err(), "expected SSRF policy violation, got Ok");
    let error_text = format!("{}", result.as_ref().err().unwrap());
    assert!(
        error_text.contains("ssrf_policy_violation"),
        "expected 'ssrf_policy_violation' in error message, got: {error_text}"
    );
}

#[tokio::test]
async fn test_ssrf_private_network_class_a_denied() {
    // 10.0.0.1 is RFC-1918 private; must be rejected by default SSRF policy.
    let engine = create_engine(None).expect("engine creation should succeed with default config");
    let result = scrape(&engine, "http://10.0.0.1:9/").await;
    assert!(result.is_err(), "expected SSRF policy violation for RFC-1918 address, got Ok");
    let error_text = format!("{}", result.as_ref().err().unwrap());
    assert!(
        error_text.contains("ssrf_policy_violation"),
        "expected 'ssrf_policy_violation' in error message, got: {error_text}"
    );
}
